import React from 'react';

import {

  Checkbox,

  LabelMoney,

  MoneyInput,

  Select,

  Tooltip,

  useDeviceContentSize,
  useViewMobileLayout,

  type SelectOption,

} from '@linm-soft-org/linm-web-common-components';

import df from '../../styles/documentForm.module.css';



export const VOUCHER_DISCOUNT_TOTAL_TOOLTIP =

  'Bật để nhập giảm giá tổng cho chứng từ. Chọn phân bổ theo số lượng hoặc tổng tiền. Không dùng khi đã nhập % giảm giá trên từng dòng hàng.';



export type VoucherMoneyFooterAmountRow = {

  id: string;

  label: string;

  amount: number;

  emphasize?: boolean;

};



export type VoucherMoneyFooterDiscountProps = {

  displayAmount: number;

  headerDiscountAmount: number;

  useHeaderDiscount: boolean;

  onUseHeaderDiscountChange: (checked: boolean) => void;

  onHeaderDiscountAmountChange: (amount: number) => void;

  allocation: 'quantity' | 'amount';

  onAllocationChange: (value: 'quantity' | 'amount') => void;

  hasLineDiscount: boolean;

  readOnly?: boolean;

};



export type VoucherMoneyFooterVarianceProps = {

  amount: number;

  onAmountChange?: (amount: number) => void;

  readOnly?: boolean;

};



export type VoucherMoneyFooterProps = {

  testIdPrefix: string;

  rows: VoucherMoneyFooterAmountRow[];

  discount?: VoucherMoneyFooterDiscountProps;

  variance?: VoucherMoneyFooterVarianceProps;

  processingLevel?: string;

  onProcessingLevelChange?: (value: string) => void;

  processingLevelOptions?: SelectOption[];

  processingLevelDisabled?: boolean;

  showProcessingLevel?: boolean;

};



const ALLOCATION_OPTIONS: SelectOption[] = [

  { value: 'quantity', label: 'Theo số lượng' },

  { value: 'amount', label: 'Theo tổng tiền' },

];



function renderAmountBlock(testIdPrefix: string, row: VoucherMoneyFooterAmountRow) {

  const amountClass = [

    df.footerAmountItem,

    row.emphasize ? df.totalBlockEmphasis : undefined,

  ].filter(Boolean).join(' ');



  return (

    <LabelMoney

      label={row.label}

      value={row.amount}

      emphasize={row.emphasize}

      className={amountClass}

      data-testid={`${testIdPrefix}-footer-${row.id}`}

    />

  );

}



function renderDiscountCheckbox(

  testIdPrefix: string,

  discount: VoucherMoneyFooterDiscountProps,

  checkboxDisabled: boolean,

) {

  return (

    <Tooltip

      content={VOUCHER_DISCOUNT_TOTAL_TOOLTIP}

      position="top"

      trigger="hover"

      inline

      allowWrap

      maxWidth={280}

      disabled={checkboxDisabled}

    >

      <span className={df.footerDiscountCheckWrap}>

        <Checkbox

          checked={discount.useHeaderDiscount}

          onChange={e => discount.onUseHeaderDiscountChange(e.target.checked)}

          disabled={checkboxDisabled}

          aria-label="Nhập giảm giá tổng"

          data-testid={`${testIdPrefix}-footer-discount-total-check`}

        />

      </span>

    </Tooltip>

  );

}



function renderDiscountCore(testIdPrefix: string, discount: VoucherMoneyFooterDiscountProps) {

  const checkboxDisabled = Boolean(discount.hasLineDiscount || discount.readOnly);

  const titleLabel = discount.useHeaderDiscount ? 'Giảm giá tổng' : 'Giảm giá:';



  return (

    <div className={df.footerDiscountCore} data-testid={`${testIdPrefix}-footer-discount`}>

      <span className={df.footerDiscountTitle} data-testid={`${testIdPrefix}-footer-discount-label`}>

        {titleLabel}

      </span>

      {renderDiscountCheckbox(testIdPrefix, discount, checkboxDisabled)}

      {discount.useHeaderDiscount ? (

        <div className={df.footerDiscountAmountInput}>

          <MoneyInput

            id={`${testIdPrefix}-footer-discount-amount`}

            aria-label="Giảm giá tổng"

            value={discount.headerDiscountAmount}

            onChange={discount.onHeaderDiscountAmountChange}

            disabled={discount.readOnly}

            data-testid={`${testIdPrefix}-footer-discount-total-amount`}

          />

        </div>

      ) : (

        <LabelMoney

          layout="value"

          variant="footer"

          value={discount.displayAmount}

          className={df.footerDiscountAmount}

          data-testid={`${testIdPrefix}-footer-discount-display`}

        />

      )}

    </div>

  );

}



function renderDiscountAllocation(
  testIdPrefix: string,
  discount: VoucherMoneyFooterDiscountProps,
  compactMoneyGrid: boolean,
) {
  return (
    <div className={df.footerAllocationInline} data-testid={`${testIdPrefix}-footer-discount-allocation-wrap`}>
      <label className={df.footerDiscountTitle} htmlFor={`${testIdPrefix}-footer-discount-allocation`}>
        Phân bổ
      </label>
      <div className={df.footerAllocationSelectWrap}>
        <Select
          id={`${testIdPrefix}-footer-discount-allocation`}
          value={discount.allocation}
          onChange={e => discount.onAllocationChange(e.target.value as 'quantity' | 'amount')}
          options={ALLOCATION_OPTIONS}
          disabled={discount.readOnly}
          fullWidth={compactMoneyGrid}
          data-testid={`${testIdPrefix}-footer-discount-allocation`}
        />
      </div>
    </div>
  );
}



function renderVarianceSlot(testIdPrefix: string, variance: VoucherMoneyFooterVarianceProps) {

  if (Math.abs(variance.amount) === 0) return null;



  if (variance.readOnly) {

    return (

      <LabelMoney

        label="Chênh lệch:"

        value={variance.amount}

        className={df.footerAmountItem}

        data-testid={`${testIdPrefix}-footer-variance`}

      />

    );

  }



  return (

    <div className={df.footerVarianceInline} data-testid={`${testIdPrefix}-footer-variance`}>

      <label className={df.footerDiscountTitle} htmlFor={`${testIdPrefix}-footer-variance-amount`}>

        Chênh lệch

      </label>

      <MoneyInput

        id={`${testIdPrefix}-footer-variance-amount`}

        value={variance.amount}

        onChange={v => variance.onAmountChange?.(v)}

        data-testid={`${testIdPrefix}-footer-variance-amount`}

      />

    </div>

  );

}



export const VoucherMoneyFooter: React.FC<VoucherMoneyFooterProps> = ({

  testIdPrefix,

  rows,

  discount,

  variance,

  processingLevel = '',

  onProcessingLevelChange,

  processingLevelOptions = [],

  processingLevelDisabled = false,

  showProcessingLevel = true,

}) => {

  const viewMobile = useViewMobileLayout();
  const { isSmall } = useDeviceContentSize();
  const compactMoneyGrid = viewMobile || isSmall;

  const footerClass = [
    df.footer,
    viewMobile ? df.footerMobile : '',
    compactMoneyGrid ? df.footerCompact : '',
  ].filter(Boolean).join(' ');



  const rowMap = new Map(rows.map(r => [r.id, r]));

  const hasVariance = Boolean(variance && Math.abs(variance.amount) !== 0);

  const hasDiscount = Boolean(discount);

  const showAllocation = Boolean(discount?.useHeaderDiscount);

  const twoMoneyRows = Boolean(rowMap.get('tax') || rowMap.get('netTotal'));



  const moneyGridClass = [

    df.footerMoneyGrid,

    compactMoneyGrid ? df.footerMoneyGridStacked : '',

    !compactMoneyGrid && twoMoneyRows ? df.footerMoneyGridTwoRow : '',

    !compactMoneyGrid && hasDiscount ? df.footerMoneyGridWithDiscount : '',

    !compactMoneyGrid && hasDiscount && showAllocation ? df.footerMoneyGridWithAllocation : '',

    !compactMoneyGrid && hasVariance ? df.footerMoneyGridWithVariance : '',

  ].filter(Boolean).join(' ');



  return (

    <div className={footerClass} data-testid={`${testIdPrefix}-footer`}>

      {showProcessingLevel ? (

        <div className={df.footerLeft} data-testid={`${testIdPrefix}-field-processingLevel`}>

          <label className={df.label} htmlFor={`${testIdPrefix}-field-processingLevel-select`}>

            Mức xử lý

          </label>

          <Select

            id={`${testIdPrefix}-field-processingLevel-select`}

            value={processingLevel}

            onChange={e => onProcessingLevelChange?.(e.target.value)}

            options={processingLevelOptions.length > 0

              ? processingLevelOptions

              : [{ value: '', label: '—' }]}

            disabled={processingLevelDisabled || processingLevelOptions.length === 0}

            fullWidth={compactMoneyGrid}

            data-testid={`${testIdPrefix}-field-processingLevel-select`}

          />

        </div>

      ) : null}



      <div className={df.footerMoneyGroup}>

        <div className={moneyGridClass}>

          {rowMap.get('productTotal') ? (

            <div className={df.footerCellProductTotal}>

              {renderAmountBlock(testIdPrefix, rowMap.get('productTotal')!)}

            </div>

          ) : null}



          {discount ? (

            <div className={df.footerCellDiscount}>

              {renderDiscountCore(testIdPrefix, discount)}

            </div>

          ) : null}



          {discount && showAllocation ? (

            <div className={df.footerCellAllocation}>

              {renderDiscountAllocation(testIdPrefix, discount, compactMoneyGrid)}

            </div>

          ) : null}



          {variance ? (

            <div className={df.footerCellVariance}>

              {renderVarianceSlot(testIdPrefix, variance)}

            </div>

          ) : null}



          {rowMap.get('tax') ? (

            <div className={df.footerCellTax}>

              {renderAmountBlock(testIdPrefix, rowMap.get('tax')!)}

            </div>

          ) : null}



          {rowMap.get('netTotal') ? (

            <div className={df.footerCellNetTotal}>

              {renderAmountBlock(testIdPrefix, rowMap.get('netTotal')!)}

            </div>

          ) : null}

        </div>

      </div>

    </div>

  );

};

