import React, { useRef } from 'react';
import { useTopbarAutoHideOnScroll } from '../../hooks/useTopbarAutoHideOnScroll';
import { useVoucherFormShellHeight } from '../../hooks/useVoucherFormShellHeight';
import df from '../../styles/documentForm.module.css';

export type SalesVoucherFormShellProps = {
  testIdPrefix: string;
  header: React.ReactNode;
  footer: React.ReactNode;
  children: React.ReactNode;
};

/**
 * Voucher full-page shell — grid 3 hàng: toolbar | scroll body | footer pin (GAP-P2-43).
 */
export const SalesVoucherFormShell: React.FC<SalesVoucherFormShellProps> = ({
  testIdPrefix,
  header,
  footer,
  children,
}) => {
  const shellRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  useVoucherFormShellHeight(shellRef);
  useTopbarAutoHideOnScroll(scrollRef);

  return (
    <div
      ref={shellRef}
      className={df.pageVoucher}
      data-voucher-form-shell
      data-testid={`${testIdPrefix}-form-shell`}
    >
      <div className={df.pageFormHeader}>{header}</div>
      <div
        ref={scrollRef}
        className={df.pageFormScroll}
        data-testid={`${testIdPrefix}-form-scroll`}
      >
        {children}
      </div>
      <div className={df.pageFormFooter} data-testid={`${testIdPrefix}-form-footer-slot`}>
        {footer}
      </div>
    </div>
  );
};
