import React from 'react';
import { MoneyInput, NumberInput, LabelMoney, DS_TEXT_END_CLASS } from '@linm-soft-org/linm-web-common-components';
import type { MaterialDto } from '../../services/master/models';
import type { OrderLineDto } from '../../services/bh/models';
import type { OrderFieldErrors, OrderLineFieldKey } from '../../utils/orderFieldValidation';
import { recalcOrderLine } from '../../utils/orderLines';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../search/LineMaterialSearchCell';
import { MaterialLinesGridActions } from './MaterialLinesGridActions';
import df from '../../styles/documentForm.module.css';

export type OrderLinesGridProps = {
  lines: OrderLineDto[];
  canEdit: boolean;
  lineErrors?: OrderFieldErrors['lines'];
  linesGeneralError?: string;
  testIdPrefix?: string;
  onChange: (lines: OrderLineDto[]) => void;
  onAddLine: () => void;
  onCopyLine: () => void;
  lineRowProps: (idx: number) => React.HTMLAttributes<HTMLTableRowElement>;
  onRemoveLine: (idx: number) => void;
  onAfterLineUpdate?: (idx: number, line: OrderLineDto, changedKey: OrderLineFieldKey) => void;
};

export const OrderLinesGrid: React.FC<OrderLinesGridProps> = ({
  lines,
  canEdit,
  lineErrors,
  linesGeneralError,
  testIdPrefix = 'order-lines',
  onChange,
  onAddLine,
  onCopyLine,
  lineRowProps,
  onRemoveLine,
  onAfterLineUpdate,
}) => {
  const tid = (suffix: string) => `${testIdPrefix}-${suffix}`;
  const updateLine = (idx: number, patch: Partial<OrderLineDto>, changedKey?: OrderLineFieldKey) => {
    const nextLine = recalcOrderLine({ ...lines[idx], ...patch });
    onChange(lines.map((l, i) => (i === idx ? nextLine : l)));
    if (changedKey && onAfterLineUpdate) {
      onAfterLineUpdate(idx, nextLine, changedKey);
    }
  };

  const handleMaterialSelect = (idx: number, material: MaterialDto) => {
    updateLine(idx, {
      materialCode: material.code,
      materialName: material.name,
      unitCode: material.unitCode || lines[idx]?.unitCode || 'Cai',
    }, 'materialCode');
  };

  const handleMaterialClear = (idx: number) => {
    updateLine(idx, { materialCode: '', materialName: '' }, 'materialCode');
  };

  return (
    <>
      {linesGeneralError ? (
        <div className={df.errorBanner} role="alert" data-testid={tid('general-error')}>
          {linesGeneralError}
        </div>
      ) : null}
      <div className={df.tableWrapper}>
        <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
          <thead>
            <tr>
              <MaterialLineTableHeaders />
              <th className={df.thAmount}>SL</th>
              <th className={df.thAmount}>Đơn giá</th>
              <th className={df.thAmount}>Thành tiền</th>
              <th className={df.thDel} />
            </tr>
          </thead>
          <tbody>
            {lines.map((line, idx) => (
              <tr key={idx} {...lineRowProps(idx)}>
                <LineMaterialSearchCell
                  materialCode={line.materialCode}
                  materialName={line.materialName ?? ''}
                  disabled={!canEdit}
                  error={lineErrors?.[idx]?.materialCode}
                  inputId={tid(`line-${idx + 1}-material`)}
                  testIdPrefix={tid(`line-${idx + 1}-material`)}
                  onSelect={m => handleMaterialSelect(idx, m)}
                  onClear={() => handleMaterialClear(idx)}
                />
                <td data-label="SL" className={df.tdAmount}>
                  <NumberInput
                    id={tid(`line-${idx + 1}-quantity`)}
                    value={line.quantity}
                    onChange={quantity => updateLine(idx, { quantity }, 'quantity')}
                    disabled={!canEdit}
                    error={lineErrors?.[idx]?.quantity}
                    data-testid={tid(`line-${idx + 1}-quantity`)}
                  />
                </td>
                <td data-label="Đơn giá" className={df.tdAmount}>
                  <MoneyInput
                    id={tid(`line-${idx + 1}-unitPrice`)}
                    value={line.unitPrice}
                    onChange={unitPrice => updateLine(idx, { unitPrice }, 'unitPrice')}
                    disabled={!canEdit}
                    error={lineErrors?.[idx]?.unitPrice}
                    data-testid={tid(`line-${idx + 1}-unitPrice`)}
                  />
                </td>
                <td data-label="Thành tiền" className={[df.tdAmount, DS_TEXT_END_CLASS].join(' ')}>
                  <LabelMoney
                    layout="value"
                    variant="cell"
                    value={line.amount}
                    data-testid={`line-${idx + 1}-amount`}
                  />
                </td>
                <td className={df.tdDel} data-label="">
                  <button
                    type="button"
                    className={df.btnDeleteLine}
                    onClick={() => onRemoveLine(idx)}
                    title="Xóa dòng"
                    disabled={!canEdit}
                  >
                    ×
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      <MaterialLinesGridActions
        canEdit={canEdit}
        onAddLine={onAddLine}
        onCopyLine={onCopyLine}
        linesCount={lines.length}
      />
    </>
  );
};
